192				ctx := cmd.Context()
193				cfg := flags.spannerConfig()
194	
195				if err := requireDestructiveConfirmation("truncate database", cfg, force); err != nil {
196					return err
197				}
198	
199				client, err := spannerutil.NewClient(ctx, cfg)
200				if err != nil {
201					return err
202				}
203				defer client.Close()
204	
205				// Query table names and their parent relationships from INFORMATION_SCHEMA.
206				iter := client.Single().Query(ctx, spanner.Statement{
207					SQL: `SELECT t.TABLE_NAME, COALESCE(t.PARENT_TABLE_NAME, '') AS PARENT_TABLE_NAME
208						  FROM INFORMATION_SCHEMA.TABLES t
209						  WHERE t.TABLE_SCHEMA = '' AND t.TABLE_NAME != 'SchemaMigrations'
210						  ORDER BY t.TABLE_NAME`,
211				})
212	
213				var tables []tableRelation
214				if err := iter.Do(func(row *spanner.Row) error {
215					var name, parent string
216					if err := row.Columns(&name, &parent); err != nil {
217						return err
218					}
219					tables = append(tables, tableRelation{name: name, parent: parent})
220					return nil
221				}); err != nil {
222					return fmt.Errorf("querying tables: %w", err)
223				}
224	
225				// Build deletion order: child tables before parent tables.
226				ordered := topologicalSort(tables)
227	
228				// Truncate each table.
229				for _, name := range ordered {
230					if _, err := client.ApplyPartitionedDML(ctx, fmt.Sprintf("DELETE FROM `%s` WHERE true", name)); err != nil {
231						return fmt.Errorf("truncating table %s: %w", name, err)
232					}
233				}
234	
235				fmt.Fprintf(cmd.OutOrStdout(), "Truncated %d tables in %s\n", len(ordered), cfg.DatabasePath())
236				return nil
237			},
238		}
